  border-top: 1px solid var(--line);
  display: grid;
  gap: 14px;
  margin-top: 18px;
  padding-top: 18px;
}

.note-list {
  display: grid;
  gap: 14px;
  margin-top: 18px;
}

.note-list-item {
  align-items: flex-start;
  border: 1px solid var(--line);
  border-radius: 20px;
  display: grid;
  gap: 12px;
  padding: 18px;
}

.note-list-link {
  font-size: 1.15rem;
  font-weight: 700;
}

.note-list-link:hover {
  color: var(--accent-strong);
}

.note-list-item p {
  line-height: 1.6;
  margin: 8px 0 0;
}

.note-meta {
  display: flex;
  flex-wrap: wrap;
  gap: 10px;
  text-transform: uppercase;
  font-size: 0.78rem;
  letter-spacing: 0.08em;
}

.link-manager-grid,
.link-form,
.link-list,
.link-list-item,
.link-list-heading,
.link-list-footer,
.tag-list,
.tag-filter-list,
.search-form,
.retrieval-grid {
  display: grid;
  gap: 16px;
}

.field-note,
.link-url,
.link-summary {
  color: var(--muted);
}

.field-note {
  line-height: 1.6;
  margin: -4px 0 0;
}

.link-list {
  margin-top: 18px;
}

.link-list-item {
  border: 1px solid var(--line);
  border-radius: 20px;
  padding: 18px;
}

.link-url,
.link-summary {
  line-height: 1.6;
  margin: 0;
  overflow-wrap: anywhere;
}

.tag-list {
  align-items: flex-start;
  grid-template-columns: repeat(auto-fit, minmax(7rem, max-content));
}

.tag-pill {
  background: rgba(138, 79, 45, 0.08);
  border: 1px solid rgba(138, 79, 45, 0.18);
  border-radius: 999px;
  color: var(--accent-strong);
  display: inline-flex;
  min-height: 2.75rem;
  align-items: center;
  padding: 0.45rem 0.9rem;
}

.tag-pill-muted {
  background: transparent;
  border-color: var(--line);
  color: var(--muted);
}

.tag-filter-list {
  grid-template-columns: repeat(auto-fit, minmax(12rem, max-content));
  margin-top: 18px;
}

.tag-filter-link {
  align-items: flex-start;
  background: rgba(255, 255, 255, 0.65);
  border: 1px solid var(--line);
  border-radius: 20px;
  color: var(--ink);
  display: grid;
  gap: 6px;
  min-height: 4.25rem;
  padding: 14px 16px;
}

.tag-filter-link-active {
  background: rgba(138, 79, 45, 0.1);
  border-color: rgba(138, 79, 45, 0.22);
}

.tag-filter-count {
  color: var(--muted);
  font-size: 0.82rem;
}

.search-form {
  align-items: end;
}

.retrieval-grid {
  grid-template-columns: minmax(0, 1fr);
}

.markdown-preview {
  border-top: 1px solid var(--line);
  margin-top: 18px;
  padding-top: 18px;
}

.markdown-preview > :first-child {
  margin-top: 0;
}

.markdown-preview > :last-child {
  margin-bottom: 0;
}

.markdown-preview h1,
.markdown-preview h2,
.markdown-preview h3,
.markdown-preview h4,
.markdown-preview h5,
.markdown-preview h6 {
  line-height: 1.1;
  margin: 1.4rem 0 0.75rem;
}

.markdown-preview h1 {
  font-size: 2rem;
}

.markdown-preview h2 {
  font-size: 1.55rem;
}

.markdown-preview h3 {
  font-size: 1.25rem;
}

.markdown-preview p,
.markdown-preview li,
.markdown-preview blockquote {
  line-height: 1.7;
}

.markdown-preview p,
.markdown-preview ul,
.markdown-preview ol,
.markdown-preview pre,
.markdown-preview blockquote {
  margin: 0 0 1rem;
}

.markdown-preview ul,
.markdown-preview ol {
  padding-left: 1.4rem;
}

.markdown-preview code {
  background: rgba(28, 22, 16, 0.08);
  border-radius: 0.4rem;
  padding: 0.12rem 0.35rem;
}

.markdown-preview pre {
  background: rgba(28, 22, 16, 0.92);
  border-radius: 1rem;
  color: #f7f2e8;
  overflow-x: auto;
  padding: 1rem;
}

.markdown-preview pre code {
  background: transparent;
  padding: 0;
}

.markdown-preview blockquote {
  border-left: 3px solid rgba(138, 79, 45, 0.35);
  margin-left: 0;
  padding-left: 1rem;
}

.markdown-preview a {
  color: var(--accent-strong);
  text-decoration: underline;
  text-underline-offset: 0.12em;
}

.bullet-list {
  display: grid;
  gap: 10px;
  line-height: 1.6;
  margin: 20px 0 0;
  padding-left: 18px;
}

.sign-in-form {
  display: grid;
  gap: 16px;
  margin-top: 24px;
}

.sign-in-form label {
  color: var(--muted);
  display: grid;
  font-size: 0.92rem;
  gap: 8px;
}

.sign-in-form input {
  background: rgba(255, 255, 255, 0.9);
  border: 1px solid var(--line);
  border-radius: 14px;
  font: inherit;
  padding: 12px 14px;
}

.button-row {
  align-items: center;
  display: flex;
  gap: 12px;
  margin-top: 8px;
}

.primary-button,
.ghost-button {
  border-radius: 999px;
  cursor: pointer;
  font: inherit;
  padding: 11px 18px;
}

.primary-button {
  background: var(--accent-strong);
  border: 0;
  color: #fff8f0;
}

.ghost-button {
  background: transparent;
  border: 1px solid var(--line);
  color: var(--ink);
}

.inline-list {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  list-style: none;
  margin: 18px 0 0;
  padding: 0;
}

.inline-list li {
  border: 1px solid var(--line);
  border-radius: 999px;
  color: var(--muted);
  padding: 8px 12px;
}

.public-hero {
  padding-bottom: 36px;
}

.public-note-card {
  max-width: 820px;
}

.public-note-body {
  margin-top: 24px;
}

@media (min-width: 768px) {
  .link-manager-grid {
    grid-template-columns: minmax(0, 0.9fr) minmax(0, 1.1fr);
    align-items: start;
  }

  .link-list-footer {
    align-items: center;
    grid-template-columns: minmax(0, 1fr) auto;
  }

  .note-editor-grid {
    grid-template-columns: minmax(0, 1.05fr) minmax(0, 0.95fr);
  }

  .note-list-item {
    grid-template-columns: minmax(0, 1fr) auto;
  }

  .retrieval-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 900px) {
  .home-grid {
    grid-template-columns: minmax(0, 1fr);
  }

  .summary-row {
    grid-template-columns: minmax(0, 1fr);
  }
}

@media (max-width: 640px) {
  .page-shell {
    padding: 18px;
  }

  .site-header {
    align-items: flex-start;
    flex-direction: column;
    gap: 12px;
  }

  .site-nav {
    flex-wrap: wrap;
  }

  .hero-card,
  .panel-card,
  .feature-card {
    padding: 24px;
  }

  .button-row {
    flex-wrap: wrap;
  }
}
